import * as t from "io-ts";
import { intentTypes } from "./intentType";
import { BaseStakeIntent } from "./baseStakeIntent";

/**
 * @title Baby WithdrawReward Intent
 *
 * @param {string} type - the stakeholder type (finality_provider, btc_staker)
 */
export const BabyWithdrawRewardIntent = t.intersection([
  BaseStakeIntent,
  t.type({
    intentType: intentTypes.stakeClaimRewards,
    type: t.string,
  }),
]);

export type BabyWithdrawRewardIntent = t.TypeOf<
  typeof BabyWithdrawRewardIntent
>;
